import{_ as e,o as s,c as r,a2 as t}from"./chunks/framework.BS3ZfcoS.js";const g=JSON.parse('{"title":"学历自救","description":"","frontmatter":{"title":"学历自救","author":"","collection":"职场成长","series_order":15,"total_chars":950},"headers":[],"relativePath":"career/degree-self-rescue.md","filePath":"career/degree-self-rescue.md"}'),o={name:"career/degree-self-rescue.md"};function p(n,a,l,i,c,h){return s(),r("div",null,[...a[0]||(a[0]=[t('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p><a href="#s-588" class="page-toc-link">学历自救系列</a>     <a href="#s-589" class="page-toc-link">学历自救（一）——高考十年回想</a>     <a href="#s-591" class="page-toc-link">学历自救（二）——选专业与人生迷茫</a>     <a href="#s-593" class="page-toc-link">学历自救（三）——二本毕业考研失败的逆袭</a>     <a href="#s-595" class="page-toc-link">学历自救（四）——学会自救</a></div><h2 id="s-588" tabindex="-1">学历自救系列 <a class="header-anchor" href="#s-588" aria-label="Permalink to &quot;学历自救系列 {#s-588}&quot;">​</a></h2><p>共4个视频</p><h3 id="s-589" tabindex="-1">学历自救（一）——高考十年回想 <a class="header-anchor" href="#s-589" aria-label="Permalink to &quot;学历自救（一）——高考十年回想 {#s-589}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **高考前自卑摆烂被喜欢的人激励奋起直追，真的考了全班第一——年轻时候情感对人的影响力极大</p><p>**2. **以为是人生最暗的日子，后来才知是最闪亮的日子——高中有明确目标和最重要的人在身边</p><h4 id="s-590" tabindex="-1">3. 大学以后一切全变了——拥有自由却不知如何利用 <a class="header-anchor" href="#s-590" aria-label="Permalink to &quot;3. 大学以后一切全变了——拥有自由却不知如何利用 {#s-590}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「我以为高考是我最黑的一段日子，但是十多年后我回想起来，我才发现其实高中是我人生当中最闪亮的一段日子」</em></p><p><strong>行动指南</strong></p><p>珍惜有明确目标的时光，找到驱动自己前进的力量</p><h3 id="s-591" tabindex="-1">学历自救（二）——选专业与人生迷茫 <a class="header-anchor" href="#s-591" aria-label="Permalink to &quot;学历自救（二）——选专业与人生迷茫 {#s-591}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-592" tabindex="-1">1. 选专业像闭着眼睛相亲结婚——多数人并不了解所学专业 <a class="header-anchor" href="#s-592" aria-label="Permalink to &quot;1. 选专业像闭着眼睛相亲结婚——多数人并不了解所学专业 {#s-592}&quot;">​</a></h4><p>**2. **适应自由比适应规则难多了——高中时期待大学的自由，但自主权到手却不知如何利用</p><p>**3. **人生比高考难——人生是开卷考试但没有标准答案，连教材参考书都不知道，写完的卷子可能10年20年后才出分数</p><p><strong>金句</strong></p><p><em>「人生比高考要难多了，难就难在人生它是一场开卷考试，可是你根本不知道标准答案是什么」</em></p><p><strong>行动指南</strong></p><p>在迷茫中主动探索，不要等待标准答案从天而降</p><h3 id="s-593" tabindex="-1">学历自救（三）——二本毕业考研失败的逆袭 <a class="header-anchor" href="#s-593" aria-label="Permalink to &quot;学历自救（三）——二本毕业考研失败的逆袭 {#s-593}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **学会谦卑——刚毕业不要对回报期望过高，月薪过万真的是一个坎，迈过去的人不多</p><p>**2. **对工作保持谦卑——你是为社会提供价值，不是社会欠你什么；不挑活，只要能长本事就干</p><h4 id="s-594" tabindex="-1">3. 从月薪5000翻译转行互联网运营两年月薪过万——城市的钱在哪里你就去哪里 <a class="header-anchor" href="#s-594" aria-label="Permalink to &quot;3. 从月薪5000翻译转行互联网运营两年月薪过万——城市的钱在哪里你就去哪里 {#s-594}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「我一直在想说我想要什么，但我却几乎没有想过说我能给别人什么」</em></p><p><strong>行动指南</strong></p><p>保持谦卑积累能力，关注能为别人提供什么价值</p><h3 id="s-595" tabindex="-1">学历自救（四）——学会自救 <a class="header-anchor" href="#s-595" aria-label="Permalink to &quot;学历自救（四）——学会自救 {#s-595}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **学会自救——把焦虑的时间用来自救；高考落榜最坏的结果不是上了烂学校，而是因此沉沦</p><p>**2. **没有烂学校只有摆烂的人——学历失去后要积极为自己争取其他新身份（好项目/好公司/里程碑成绩）</p><p>**3. **真正决定你是谁的是每天日复一日做的事——大事件的影响有保质期，保质期一过只有日常行为定义你</p><p><strong>金句</strong></p><p><em>「真正能够决定你是谁的，其实是你每天日复一日在做的事情」</em></p><p><strong>行动指南</strong></p><p>每年设定里程碑式成绩，用持续行动而非一纸学历定义自己</p>',39)])])}const u=e(o,[["render",p]]);export{g as __pageData,u as default};
